drop function report_pood19;--get full_name ap_member report_pood19

CREATE OR REPLACE FUNCTION erp.report_pood19(p_lin_id character varying, p_pur_ord_master_id integer)
 RETURNS TABLE(pur_ord_master_id integer, program_header character varying, program_name character varying, h1 character varying, h2 character varying, h3 character varying, d1 character varying, d1_1 character varying, d1_2 character varying, d2 character varying, d2_0 character varying, d2_1 character varying, d2_2 character varying, d2_3 character varying, d2_4 character varying, d2_f1_1 character varying, d2_f1_2 character varying, d2_f1_3 character varying, d2_f1_4 character varying, d2_f2 character varying, d2_f3 character varying, d3 character varying, d3_1 character varying, d3_2 character varying, d3_3 character varying, d3_4 character varying, d4_1 character varying, d4_1_0 character varying, d4_1_0_1 character varying, d4_1_0_2 character varying, d4_1_1 character varying, d4_1_2 character varying, d4_1_3 character varying, d4_1_4 character varying, d4_1_f1 character varying, d4_1_f2 character varying, d4_1_f3 character varying, d4_2 character varying, d4_2_0 character varying, d4_2_0_1 character varying, d4_2_1 character varying, d4_2_2 character varying, d4_2_f character varying, d4_2_f1 character varying, d4_2_f2 character varying, d5 character varying, d5_0_0 character varying, d5_0_1 character varying, d5_1 character varying, d5_2 character varying, d5_3_1 character varying, d5_3_2 character varying, d5_4 character varying, d5_5 character varying, d5_6_1 character varying, d5_6_1_1 character varying, d5_6_1_2 character varying, d5_6_2 character varying, d5_6_2_1 character varying, d5_6_2_2 character varying, d6 character varying, d6_1 character varying, d6_2 character varying, d7_1 character varying, d7_1_1 character varying, d7_1_2 character varying, d7_1_3 character varying, d7_1_4 character varying, d7_2 character varying, d7_2_1 character varying, d7_2_2 character varying, d8 character varying, d8_1 character varying, d8_2 character varying, d8_3 character varying, d9 character varying, d9_1 character varying, d9_2 character varying, d10 character varying, d10_1 character varying, d10_2 character varying, d11 character varying, d11_1 character varying, d11_2 character varying, d11_3 character varying, d12 character varying, d12_1 character varying, d12_2 character varying, d12_3 character varying, d13 character varying, d13_1 character varying, d13_2 character varying, d14 character varying, d14_1 character varying, d15 character varying, d15_1 character varying, d16 character varying, d16_1 character varying, d17 character varying, d17_1 character varying, d17_2 character varying, d18 character varying, d18_1 character varying, d18_2 character varying, d19 character varying, d19_1 character varying, d19_2 character varying, d19_3 character varying, d20 character varying, d20_1 character varying, d21 character varying, d21_1 character varying, d21_2 character varying, d21_3 character varying, d22 character varying, d22_1 character varying, d22_2 character varying, d22_3 character varying, d22_4 character varying, d23 character varying, d23_0 character varying, d23_1 character varying, d23_2 character varying, d23_f character varying, d23_f1 character varying, d23_f2 character varying, sys1 character varying, sys2 character varying, sys3 character varying, sys4 character varying, sys5 character varying, sys6 character varying, sys7 character varying, sys8 character varying, f0 character varying, f1 character varying, f2 character varying, f3 character varying, f4 character varying, f4_1 character varying, f4_2 character varying, f5 character varying, f6 character varying, f7 character varying, f8 character varying, f8_1 character varying, f8_2 character varying, f8_3 character varying, f8_4 character varying, f8_5 character varying, f9 character varying, f10 character varying, f11 character varying, f12 character varying, f13 character varying, f14 character varying, f15 character varying, f16 character varying, f17 character varying, f18 character varying, f19 character varying, f20 character varying, f21 character varying, f22 character varying, f23 character varying, f24 character varying, recipient_sign_image character varying, sign_name character varying)
 LANGUAGE plpgsql
AS $function$
BEGIN
    RETURN QUERY
select a.pur_ord_master_id::integer as pur_ord_master_id,
		concat('แบบสัญญา')::character varying as program_header,
		concat('สัญญาจ้างก่อสร้าง')::character varying as program_name,
		concat('สัญญาเลขที่ ', a.ref_no)::character varying as h1,
		concat(
			'สัญญาฉบับนี้ทำขึ้น ณ ',
			(select l.company_name from db_company_lang l where l.company_code = a.company_code and lower(l.language_code) = lower(p_lin_id)),
			' ตำบล/แขวง ',
			(select get_sub_district_name(dcl.language_code,dcl.sub_district_id) from db_company_lang dcl
			where dcl.company_code = a.company_code and lower(dcl.language_code) = lower(p_lin_id)),
			' อำเภอ/เขต ',
			(select get_district_name(dcl.language_code,dcl.district_id) from db_company_lang dcl 
			where dcl.company_code = a.company_code and lower(dcl.language_code) = lower(p_lin_id)),
			' จังหวัด ',
			(select get_province_name(dcl.language_code,dcl.province_id) from db_company_lang dcl
			where dcl.company_code = a.company_code and lower(dcl.language_code) = lower(p_lin_id)),
			' ',
			(select po_format_date_thai('เมื่อวันที่','เดือน','พ.ศ.',a.po_date::date,p_lin_id )),
			' ระหว่าง ',
			(select l.company_name from db_company_lang l where l.company_code = a.company_code and lower(l.language_code) = lower(p_lin_id)),
			' โดย ',
			(select signde.emp_name from db_employee_name(p_lin_id) signde where signde.emp_id = a.sign_id),
			' ',
			a.sign_posi,
			' ',
			a.approve_posi,
			' ซึ่งต่อไปในสัญญานี้เรียกว่า “ผู้ว่าจ้าง” ฝ่ายหนึ่ง กับ ',
			case 
				when am.juristic_type = 'Y' -- นิติบุคคล
					then (select concat(coalesce(aml.full_name, coalesce(aml2.prefix_abbreviation, aml2.prefix_name), ' ', aml.first_name, ' ', aml.last_name),
										' อยู่บ้านเลขที่ ',am.house_no,' ถนน ',am.road ,
										' ตำบล/แขวง ',get_sub_district_name(p_lin_id,am.sub_district_id),
										' อำเภอ/เขต ',get_district_name(p_lin_id,am.district_id),
										' จังหวัด ',get_province_name(p_lin_id,am.province_id),
										' ผู้ถือบัตรประจำตัวประชาชนเลขที่ ',
										am.tax_id,
										' ดังปรากฏตามสำเนาบัตรประจำตัวประชาชนแนบท้ายสัญญานี้ ซึ่งต่อไปในสัญญานี้เรียกว่า “ผู้รับจ้าง” อีกฝ่ายหนึ่ง'
										))
				else (select concat(coalesce(aml.full_name, coalesce(aml2.prefix_abbreviation, aml2.prefix_name), ' ', aml.first_name, ' ', aml.last_name),' ซึ่งจดทะเบียนเป็นนิติบุคคล ณ …………………………………………………………………………………… ',
										'มีสำนักงานใหญ่อยู่เลขที่ ',am.house_no,' ถนน ',am.road ,
										' ตำบล/แขวง ',get_sub_district_name(p_lin_id,am.sub_district_id),
										' อำเภอ/เขต ',get_district_name(p_lin_id,am.district_id),
										' จังหวัด ',get_province_name(p_lin_id,am.province_id),
										' โดย ………………………………………………… ผู้มีอำนาจลงนามผูกพันนิติบุคคลปรากฏตามหนังสือรับรองของสำนักงานทะเบียนหุ้นส่วนบริษัท ………… ลงวันที่ ………………………… (5) (และหนังสือมอบอำนาจลงวันที่ ………………………… ) แนบท้ายสัญญานี้ (6) ซึ่งต่อไปในสัญญานี้เรียกว่า “ผู้รับจ้าง” อีกฝ่ายหนึ่ง'
										))
			end
			)::character varying as h2,
		concat('คู่สัญญาได้ตกลงกันมีข้อความดังต่อไปนี้')::character varying as h3,
		concat('ข้อ 1 ข้อตกลงว่าจ้าง')::character varying as d1,
		concat('ผู้ว่าจ้างตกลงจ้างและผู้รับจ้างตกลงรับจ้างทำงาน….……….…….…(7)…….…...….……… ณ …..……………................... ตำบล/แขวง….…………………………….…….. อำเภอ/เขต.........…………..…………..…จังหวัด……………………….……….….. ตามข้อกำหนดและเงื่อนไขแห่งสัญญานี้รวมทั้งเอกสารแนบท้ายสัญญา')::character varying as d1_1,
		concat('ผู้รับจ้างตกลงที่จะจัดหาแรงงานและวัสดุ เครื่องมือเครื่องใช้ ตลอดจนอุปกรณ์ต่างๆ ชนิดดีเพื่อใช้ในงานจ้างตามสัญญานี้')::character varying as d1_2,
		concat('ข้อ 2 เอกสารอันเป็นส่วนหนึ่งของสัญญา')::character varying as d2,
		concat('เอกสารแนบท้ายสัญญาดังต่อไปนี้ให้ถือเป็นส่วนหนึ่งของสัญญานี้')::character varying as d2_0,
		concat('2.1 ผนวก 1 .…….….(แบบรูป)……........…......….......…..')::character varying as d2_1,
		concat('2.2 ผนวก 2 ………...(รายการละเอียด)…….....…….......')::character varying as d2_2,
		concat('2.3 ผนวก 3 …........(ใบแจ้งปริมาณงานและราคา)......')::character varying as d2_3,
		concat('2.4 ผนวก 4 ……….(ใบเสนอราคา)….........………….......')::character varying as d2_4,
		concat('จำนวน......(......) หน้า')::character varying as d2_f1_1,
		concat('จำนวน......(......) หน้า')::character varying as d2_f1_2,
		concat('จำนวน......(......) หน้า')::character varying as d2_f1_3,
		concat('จำนวน......(......) หน้า')::character varying as d2_f1_4,
		concat('…….…………………………..ฯลฯ.…….…………………………..')::character varying as d2_f2,
		concat('ความใดในเอกสารแนบท้ายสัญญาที่ขัดหรือแย้งกับข้อความในสัญญานี้ ให้ใช้ข้อความ ในสัญญานี้บังคับ และในกรณีที่เอกสารแนบท้ายสัญญาขัดแย้งกันเอง ผู้รับจ้างจะต้องปฏิบัติตามคำวินิจฉัยของผู้ว่าจ้าง คำวินิจฉัยของผู้ว่าจ้างให้ถือเป็นที่สุด และผู้รับจ้างไม่มีสิทธิเรียกร้องค่าจ้าง ค่าเสียหายหรือค่าใช้จ่ายใด ๆ เพิ่มเติมจากผู้ว่าจ้างทั้งสิ้น')::character varying as d2_f3,
		concat('ข้อ 3 หลักประกันการปฏิบัติตามสัญญา')::character varying as d3,
		concat('ในขณะทำสัญญานี้ผู้รับจ้างได้นำหลักประกันเป็น ',(select string_agg(concat(pgtl.guaranty_type_name, ' เป็นจำนวนเงิน ' ,TO_CHAR(pgm.collateral_amt, 'FM999G999G999D00'), ' บาท ','( ', po_baht_text(pgm.collateral_amt::numeric), ' ) '),', ')
                                                from po_guaranty_master pgm 
                                                left join po_guaranty_detail pgd on pgm.guaranty_master_id = pgd.guaranty_master_id 
                                                left join po_guaranty_type pgt on pgd.guaranty_type = pgt.guaranty_type_code 
                                                        left join po_guaranty_type_lang pgtl on pgt.guaranty_type_id = pgtl.guaranty_type_id 
                                                                and lower(pgtl.language_code) = lower(p_lin_id)
                                                where pgm.status <> 'C' and pgm.ref_doc_type = a.doc_type and pgm.ref_doc_no = a.po_no),
                'ซึ่งเท่ากับร้อยละ……….…(9)……...…(…………..………...) ของราคาค่าจ้างตามสัญญา มามอบให้แก่ผู้ว่าจ้างเพื่อเป็น หลักประกันการปฏิบัติตามสัญญานี้')::character varying as d3_1,
		concat('(10) กรณีผู้รับจ้างใช้หนังสือค้ำประกันมาเป็นหลักประกันการปฏิบัติตามสัญญา หนังสือค้ำประกันดังกล่าว จะต้องออกโดยธนาคารที่ประกอบกิจการในประเทศไทย หรือโดยบริษัทเงินทุนหรือบริษัทเงินทุนหลักทรัพย์ที่ได้รับอนุญาต ให้ประกอบกิจการเงินทุนเพื่อการพาณิชย์และประกอบธุรกิจ ค้ำประกันตามประกาศของธนาคารแห่งประเทศไทยตามรายชื่อบริษัทเงินทุน ที่ธนาคารแห่งประเทศไทยแจ้งเวียนให้ทราบตามแบบที่คณะกรรมการนโยบายการจัดซื้อจัดจ้างและการบริหารพัสดุภาครัฐกำหนด หรืออาจเป็นหนังสือค้ำประกันอิเล็กทรอนิกส์ตามวิธีการที่กรมบัญชีกลางกำหนดก็ได้ และจะต้องมีอายุการค้ำประกันตลอดไปจนกว่า ผู้รับจ้างพ้นข้อผูกพันตามสัญญานี้')::character varying as d3_2,
		concat('หลักประกันที่ผู้รับจ้างนำมามอบให้ตามวรรคหนึ่ง จะต้องมีอายุครอบคลุมความรับผิดทั้งปวงของผู้รับจ้าง ตลอดอายุสัญญา ถ้าหลักประกันที่ผู้รับจ้างนำมามอบให้ดังกล่าวลดลงหรือเสื่อมค่าลง หรือมีอายุไม่ครอบคลุมถึงความรับผิดของผู้รับจ้าง ตลอดอายุสัญญาไม่ว่าด้วยเหตุใดๆ ก็ตามรวมถึงกรณี ผู้รับจ้างส่งมอบงานล่าช้าเป็นเหตุให้ ระยะเวลาแล้วเสร็จหรือวันครบกำหนดความรับผิด ในความชำรุดบกพร่อง ตามสัญญาเปลี่ยนแปลงไป ไม่ว่าจะเกิดขึ้นคราวใดผู้รับจ้างต้อง หาหลักประกันใหม่หรือหลักประกันเพิ่มเติม ให้มีจำนวนครบถ้วนตามวรรคหนึ่งมามอบให้แก่ผู้ว่าจ้างภายใน...........(…….….) วัน นับถัดจากวันที่ได้รับแจ้งเป็นหนังสือจากผู้ว่าจ้าง')::character varying as d3_3,
		concat('หลักประกันที่ผู้รับจ้างนำมามอบไว้ตามข้อนี้ ผู้ว่าจ้างจะคืนให้แก่ผู้รับจ้างโดยไม่มีดอกเบี้ยเมื่อผู้รับจ้างพ้นจากข้อผูกพัน และความรับผิดทั้งปวงตามสัญญานี้แล้ว')::character varying as d3_4,
		concat('ข้อ 4 (ก) ค่าจ้างและการจ่ายเงิน')::character varying as d4_1,
		concat('(สำหรับสัญญาที่เป็นราคาต่อหน่วย)')::character varying as d4_1_0,
		concat('ผู้ว่าจ้างตกลงจ่ายและผู้รับจ้างตกลงรับเงินค่าจ้างเป็นจำนวนเงิน ',TO_CHAR(a.gs_aft_disc, 'FM999G999G999D00'),' บาท ',' ( ',po_baht_text(a.gs_aft_disc::numeric),' ) ',
				'ซึ่งได้รวมภาษีมูลค่าเพิ่มจำนวน ',TO_CHAR(a.total_vat_amt, 'FM999G999G999D00'),' บาท ',' ( ',po_baht_text(a.total_vat_amt::numeric),' ) ',
				'ตลอดจนภาษีอากรอื่น ๆ และค่าใช้จ่ายทั้งปวงด้วยแล้ว โดย ถือราคาต่อหน่วยเป็นเกณฑ์ตามรายการ แต่ละประเภทดังที่ได้กำหนดไว้ในใบแจ้งปริมาณงานและราคา ตามเอกสารแนบท้ายสัญญาผนวก 3')::character varying as d4_1_0_1,
		concat('คู่สัญญาทั้งสองฝ่ายต่างตกลงว่าจำนวนปริมาณงานที่กำหนดไว้ในบัญชีรายการก่อสร้างหรือใบแจ้งปริมาณงานและ ราคานี้เป็นจำนวนโดยประมาณเท่านั้น จำนวนปริมาณงานที่แท้จริงอาจจะมากหรือน้อยกว่านี้ก็ได้ ซึ่งผู้ว่าจ้างจะจ่ายเงินค่าจ้างให้แก่ผู้รับจ้าง ตามราคาต่อหน่วยของงาน แต่ละรายการที่ได้ทำเสร็จจริง คู่สัญญาทั้งสองฝ่ายต่างตกลงที่จะไม่เปลี่ยนแปลงราคาต่อหน่วย หรือเรียกร้องค่า สินไหมทดแทนอันเกิดจากการที่จำนวนปริมาณงานในแต่ละรายการได้แตกต่างไปจากที่กำหนดไว้ในสัญญา ทั้งนี้ นอกจากในกรณีต่อไปนี้ (11)')::character varying as d4_1_0_2,
		concat('4.1 เมื่อปริมาณงานที่ทำเสร็จจริงในส่วนที่เกินกว่าร้อยละ 125 (หนึ่งร้อยยี่สิบห้า) แต่ไม่เกินร้อยละ 150 (หนึ่งร้อยห้าสิบ) ของปริมาณงานที่กำหนดไว้ในสัญญาหรือใบแจ้งปริมาณงาน และราคา จะจ่ายให้ในอัตราร้อยละ 90 (เก้าสิบ) ของราคาต่อหน่วยตามสัญญา')::character varying as d4_1_1,
		concat('4.2 เมื่อปริมาณงานที่ทำเสร็จจริงในส่วนที่เกินกว่าร้อยละ 150 (หนึ่งร้อยห้าสิบ) ของปริมาณงานที่กำหนดไว้ในสัญญา หรือใบแจ้งปริมาณงานและราคา จะจ่ายให้ในอัตราร้อยละ 83 (แปดสิบสาม) ของราคาต่อหน่วยตามสัญญา')::character varying as d4_1_2,
		concat('4.3 เมื่อปริมาณงานที่ทำเสร็จจริงน้อยกว่าร้อยละ 75 (เจ็ดสิบห้า) ของปริมาณงานที่กำหนดไว้ในสัญญาหรือ ใบแจ้ง ปริมาณงานและราคา จะจ่ายให้ตามราคาต่อหน่วยในสัญญาและจะจ่ายเพิ่มชดเชยเป็นค่า Overhead และ Mobilization สำหรับงานรายการ นั้นในอัตราร้อยละ 17 (สิบเจ็ด) ของผลต่างระหว่างปริมาณงานทั้งหมดของงานรายการนั้นตามสัญญา โดยประมาณกับปริมาณงานที่ ทำเสร็จจริงคูณด้วยราคาต่อหน่วยตามสัญญา ทั้งนี้ การจ่ายเงินเพิ่มชดเชยเป็นค่า Overhead และ Mobilizationดังกล่าว ผู้ว่าจ้างจะจ่าย ให้แก่ผู้รับจ้างในงวดสุดท้ายของการจ่ายเงินค่างานตามสัญญา')::character varying as d4_1_3,
		concat('4.4 ผู้ว่าจ้างจะจ่ายเงินที่เพิ่มขึ้นตามข้อ 4.1 หรือ 4.2 ดังกล่าวข้างต้น ในงวดสุดท้ายของการจ่ายเงินหรือ ก่อนงวด สุดท้ายของการจ่ายเงินตามที่ผู้ว่าจ้างจะพิจารณาเห็นสมควร เว้นแต่กรณี ที่ผู้ว่าจ้างพิจารณาเห็นว่าปริมาณงานที่ทำเสร็จจริงดังกล่าวมิได้มี ส่วนเกี่ยวข้องกับงานอื่นที่เหลือ อีกทั้งงานที่เหลืออยู่ก็มิได้มีผลกระทบต่อการจ่ายเงินค่างานที่แล้วเสร็จจริงในงวดดังกล่าว ทั้งนี้ ผู้ว่าจ้าง  อาจจ่ายเงินที่เพิ่มขึ้นให้แก่ผู้รับจ้างพร้อมกับการจ่ายเงินค่างานงวดนั้น ๆ และการพิจารณาว่างานใด อยู่ในหลักเกณฑ์ดังกล่าวหรือไม่ เป็นดุลพินิจโดยเด็ดขาดของผู้ว่าจ้าง')::character varying as d4_1_4,
		concat('ผู้ว่าจ้างตกลงที่จะจ่ายเงินค่าจ้างให้แก่ผู้รับจ้างเป็นรายเดือนตามเนื้องานที่ทำเสร็จจริง เมื่อผู้ว่าจ้างหรือเจ้าหน้าที่ ของผู้ว่าจ้างได้ทำการตรวจสอบผลงานที่ทำเสร็จแล้ว และปรากฏว่าเป็นที่พอใจ ตรงตามข้อกำหนดแห่งสัญญานี้ทุกประการ ผู้ว่าจ้างจะ ออกหนังสือรับรองการรับมอบงานนั้น ให้ไว้แก่ผู้รับจ้าง')::character varying as d4_1_f1,
		concat('การจ่ายเงินงวดสุดท้ายจะจ่ายให้เมื่องานทั้งหมดตามสัญญาได้แล้วเสร็จทุกประการรวมทั้งการทำสถานที่ก่อสร้าง ให้สะอาดเรียบร้อยตามที่กำหนดไว้ในข้อ 20')::character varying as d4_1_f2,
		concat('(12) การจ่ายเงินตามเงื่อนไขแห่งสัญญานี้ ผู้ว่าจ้างจะโอนเงินเข้าบัญชีเงินฝากธนาคารของผู้รับจ้าง ชื่อธนาคาร….....………....….………….สาขา………..….…….…..ชื่อบัญชี……………………………………เลขที่บัญชี…………………………………ทั้งนี้ ผู้รับจ้างตกลงเป็นผู้รับภาระเงินค่าธรรมเนียมหรือค่าบริการอื่นใดเกี่ยวกับการโอน รวมทั้งค่าใช้จ่ายอื่นใด (ถ้ามี) ที่ธนาคารเรียกเก็บ และยินยอมให้มีการหักเงินดังกล่าวจาก จำนวนเงินโอนในงวดนั้นๆ (ความในวรรคนี้ใช้สำหรับกรณีที่หน่วยงานของรัฐจะจ่ายเงินตรง ให้แก่ผู้รับจ้าง (ระบบ Direct Payment) โดยการโอนเงินเข้าบัญชีเงินฝากธนาคารของผู้รับจ้าง ตามแนวทางที่กระทรวงการคลังหรือ หน่วยงานของรัฐเจ้าของงบประมาณเป็นผู้กำหนด แล้วแต่กรณี)')::character varying as d4_1_f3,
		concat('ข้อ 4 (ข) ค่าจ้างและการจ่ายเงิน')::character varying as d4_2,
		concat('(สำหรับสัญญาที่เป็นราคาเหมารวม)')::character varying as d4_2_0,
		concat('ผู้ว่าจ้างตกลงจ่ายและผู้รับจ้างตกลงรับเงินค่าจ้างจำนวนเงิน ',TO_CHAR(a.gs_aft_disc, 'FM999G999G999D00'),' บาท ',' ( ',po_baht_text(a.gs_aft_disc::numeric),' ) ',
				'ซึ่งได้รวมภาษีมูลค่าเพิ่มจำนวน ',TO_CHAR(a.total_vat_amt, 'FM999G999G999D00'),' บาท ',' ( ',po_baht_text(a.total_vat_amt::numeric),' ) ',
				'ตลอดจนภาษีอากรอื่น ๆ และค่าใช้จ่ายทั้งปวงด้วยแล้ว โดยถือราคาเหมารวมเป็นเกณฑ์ และกำหนดการจ่ายเงินเป็นงวดๆ ดังนี้')::character varying as d4_2_0_1,
		concat('งวดที่ 1 เป็นจำนวนเงิน……………….………...บาท (…………………………………...………….) เมื่อผู้รับจ้าง ได้ปฏิบัติงาน……………………………………ให้แล้วเสร็จภายใน…………………………………………………..')::character varying as d4_2_1,
		concat('งวดที่ 2 เป็นจำนวนเงิน…….………………...บาท (…………………………………...………….) เมื่อผู้รับจ้าง ได้ปฏิบัติงาน…………………………..…..……ให้แล้วเสร็จภายใน………………………………………………….')::character varying as d4_2_2,
		concat('…….…………………………..ฯลฯ.…….…………………………..')::character varying as d4_2_f,
		concat('งวดสุดท้าย เป็นจำนวนเงิน……………..………....บาท (…………………………………...….…..) เมื่อผู้รับจ้างได้ปฏิบัติงานทั้งหมด ให้แล้วเสร็จเรียบร้อยตามสัญญา รวมทั้งทำสถานที่ก่อสร้างให้สะอาดเรียบร้อยตามที่กำหนดไว้ในข้อ 20')::character varying as d4_2_f1,
		concat('(13) การจ่ายเงินตามเงื่อนไขแห่งสัญญานี้ ผู้ว่าจ้างจะโอนเงินเข้าบัญชีเงินฝากธนาคารของผู้รับจ้าง ชื่อธนาคาร……………….….…….….สาขา……….…..…….…….…..ชื่อบัญชี……………………………………เลขที่บัญชี……………………………….… ทั้งนี้ ผู้รับจ้างตกลงเป็นผู้รับภาระเงินค่าธรรมเนียมหรือค่าบริการอื่นใดเกี่ยวกับการโอน รวมทั้งค่าใช้จ่ายอื่นใด (ถ้ามี) ที่ธนาคารเรียกเก็บ และยินยอมให้มีการหักเงินดังกล่าวจากจำนวนเงินโอนในงวดนั้นๆ (ความในวรรคนี้ใช้สำหรับกรณีที่หน่วยงานของรัฐจะจ่ายเงินตรงให้แก่ ผู้รับจ้าง (ระบบ Direct Payment) โดยการโอนเงินเข้าบัญชีเงินฝากธนาคารของผู้รับจ้าง ตามแนวทางที่กระทรวงการคลังหรือหน่วยงาน ของรัฐเจ้าของงบประมาณเป็นผู้กำหนด แล้วแต่กรณี)')::character varying as d4_2_f2,
		concat('ข้อ 5 เงินค่าจ้างล่วงหน้า')::character varying as d5,
		concat('ผู้ว่าจ้างตกลงจ่ายเงินค่าจ้างล่วงหน้าให้แก่ผู้รับจ้าง เป็นจำนวนเงิน…………..…..…บาท(………………..….…) ซึ่งเท่ากับร้อยละ……....…(……….…………....) ของราคาค่าจ้าง ตามสัญญาที่ระบุไว้ในข้อ 4')::character varying as d5_0_0,
		concat('เงินค่าจ้างล่วงหน้าดังกล่าวจะจ่ายให้ภายหลังจากที่ผู้รับจ้างได้วางหลักประกันการรับเงินค่าจ้างล่วงหน้า เป็น............................(หนังสือค้ำประกันหรือหนังสือค้ำประกันอิเล็กทรอนิกส์ของธนาคารภายในประเทศหรือพันธบัตรรัฐบาลไทย) …………………....เต็มตามจำนวนเงินค่าจ้างล่วงหน้านั้นให้แก่ผู้ว่าจ้างผู้รับจ้างจะต้องออกใบเสร็จรับเงินค่าจ้างล่วงหน้าตามแบบที่ผู้ว่าจ้าง กำหนดให้ และผู้รับจ้างตกลงที่จะกระทำตามเงื่อนไขอันเกี่ยวกับการใช้จ่ายและการใช้คืนเงินค่าจ้างล่วงหน้านั้น ดังต่อไปนี้')::character varying as d5_0_1,
		concat('5.1 ผู้รับจ้างจะใช้เงินค่าจ้างล่วงหน้านั้นเพื่อเป็นค่าใช้จ่ายในการปฏิบัติงานตามสัญญาเท่านั้น หากผู้รับจ้างใช้จ่ายเงิน ค่าจ้างล่วงหน้าหรือส่วนใดส่วนหนึ่งของเงินค่าจ้างล่วงหน้านั้นในทางอื่น ผู้ว่าจ้างอาจจะเรียกเงินค่าจ้างล่วงหน้านั้นคืนจากผู้รับจ้างหรือ บังคับเอาจากหลักประกันการรับเงินค่าจ้างล่วงหน้าได้ทันที')::character varying as d5_1,
		concat('5.2 เมื่อผู้ว่าจ้างเรียกร้อง ผู้รับจ้างต้องแสดงหลักฐานการใช้จ่ายเงินค่าจ้างล่วงหน้า เพื่อพิสูจน์ว่าได้เป็นไปตามข้อ 5.1 ภายในกำหนด 15 (สิบห้า) วัน นับถัดจากวันได้รับแจ้งเป็นหนังสือจาก ผู้ว่าจ้าง หากผู้รับจ้างไม่อาจแสดงหลักฐานดังกล่าว ภายในกำหนด 15 (สิบห้า) วัน ผู้ว่าจ้างอาจเรียกเงินค่าจ้างล่วงหน้าคืนจากผู้รับจ้างหรือบังคับเอาจากหลักประกันการรับเงินค่าจ้างล่วงหน้าได้ทันที')::character varying as d5_2,
		concat('(15) 5.3 (ก) (สำหรับสัญญาที่เป็นราคาต่อหน่วย) ในการจ่ายเงินค่าจ้างให้แก่ผู้รับจ้างตามข้อ 4 (ก) ผู้ว่าจ้างจะหัก เงินค่าจ้าง ในแต่ละเดือนเพื่อชดใช้คืนเงินค่าจ้างล่วงหน้าไว้จำนวนร้อยละ................(..................) ของจำนวนเงินค่าจ้างในแต่ละเดือน (16) ทั้งนี้ จนกว่าจำนวนเงินที่หักไว้จะครบตามจำนวนเงินค่าจ้างล่วงหน้าที่ผู้รับจ้างได้รับไปแล้ว ยกเว้นค่าจ้างเดือนสุดท้ายจะหักไว้เป็นจำนวน เท่ากับจำนวนเงินค่าจ้างล่วงหน้าที่เหลือทั้งหมด')::character varying as d5_3_1,
		concat('(17) 5.3 (ข) (สำหรับสัญญาที่เป็นราคาเหมารวม) ในการจ่ายเงินค่าจ้างให้แก่ผู้รับจ้างตามข้อ 4 (ข) ผู้ว่าจ้างจะหัก เงินค่าจ้าง ในแต่ละงวดเพื่อชดใช้คืนเงินค่าจ้างล่วงหน้าไว้จำนวนร้อยละ..............(......................) ของจำนวนเงินค่าจ้างในแต่ละงวดจนกว่า จำนวนเงินที่หักไว้จะครบตามจำนวนเงินค่าจ้างล่วงหน้าที่ผู้รับจ้างได้รับไปแล้ว ยกเว้นค่าจ้างงวดสุดท้ายจะหักไว้เป็นจำนวนเท่ากับจำนวนเงิน ค่าจ้างล่วงหน้าที่เหลือทั้งหมด')::character varying as d5_3_2,
		concat('5.4 เงินจำนวนใด ๆ ก็ตามที่ผู้รับจ้างจะต้องจ่ายให้แก่ผู้ว่าจ้างเพื่อชำระหนี้หรือ เพื่อชดใช้ความรับผิดต่าง ๆ ตามสัญญา ผู้ว่าจ้างจะหักเอาจากเงินค่าจ้างงวดที่จะจ่ายให้แก่ผู้รับจ้างก่อนที่จะหักชดใช้คืนเงินค่าจ้างล่วงหน้า')::character varying as d5_4,
		concat('5.5 ในกรณีที่มีการบอกเลิกสัญญา หากเงินค่าจ้างล่วงหน้าที่เหลือเกินกว่าจำนวนเงินที่ผู้รับจ้างจะได้รับหลังจาก หักชดใช้ในกรณีอื่นแล้ว ผู้รับจ้างจะต้องจ่ายคืนเงินจำนวนที่เหลือนั้นให้แก่ผู้ว่าจ้าง ภายใน 7 (เจ็ด) วัน นับถัดจากวันได้รับแจ้งเป็นหนังสือ จากผู้ว่าจ้าง')::character varying as d5_5,
		concat('5.6 (ก) (สำหรับสัญญาที่เป็นราคาต่อหน่วย) ผู้ว่าจ้างจะคืนหลักประกันการรับเงินค่าจ้างล่วงหน้าให้แก่ผู้รับจ้าง ต่อเมื่อ ผู้ว่าจ้างได้หักเงินค่าจ้างไว้ครบจำนวนเงินค่าจ้างล่วงหน้าตามข้อ 5.3 (ก) แล้ว เว้นแต่ในกรณีดังต่อไปนี้ ผู้รับจ้างมีสิทธิขอคืนหลักประกัน การรับเงินค่าจ้างล่วงหน้าบางส่วนก่อนได้')::character varying as d5_6_1,
		concat('(1) กรณีผู้รับจ้างได้วางหลักประกันการรับเงินค่าจ้างล่วงหน้าไว้ฉบับเดียว หากผู้ว่าจ้างได้หักเงินค่าจ้างล่วงหน้า ไปแล้ว ผู้รับจ้างมีสิทธิขอคืนหลักประกันการรับเงินค่าจ้างล่วงหน้าในส่วนที่ผู้ว่าจ้างได้หักเงินค่าจ้างล่วงหน้าไปแล้วนั้น โดยผู้รับจ้างจะต้อง นำหลักประกันการรับเงินค่าจ้างล่วงหน้าฉบับใหม่ที่มีมูลค่าเท่ากับเงินค่าจ้างล่วงหน้าที่เหลืออยู่มาวางให้แก่ผู้ว่าจ้าง')::character varying as d5_6_1_1,
		concat('(2) กรณีผู้รับจ้างได้วางหลักประกันการรับเงินค่าจ้างล่วงหน้าไว้หลายฉบับ ซึ่งแต่ละฉบับมีมูลค่าเท่ากับจำนวนเงิน ค่าจ้างล่วงหน้าที่ผู้ว่าจ้างจะต้องหักไว้ในแต่ละงวด หากผู้ว่าจ้าง ได้หักเงินค่าจ้างล่วงหน้าในงวดใดแล้ว ผู้รับจ้างมีสิทธิขอคืนหลักประกัน การรับเงินค่าจ้างล่วงหน้าในงวดนั้นได้')::character varying as d5_6_1_2,
		concat('5.6 (ข) (สำหรับสัญญาที่เป็นราคาเหมารวม) ผู้ว่าจ้างจะคืนหลักประกันการรับเงินค่าจ้างล่วงหน้าให้แก่ผู้รับจ้าง ต่อเมื่อผู้ว่าจ้างได้หักเงินค่าจ้างไว้ครบจำนวนเงินค่าจ้างล่วงหน้าตามข้อ 5.3 (ข) แล้ว เว้นแต่ในกรณีดังต่อไปนี้ ผู้รับจ้างมีสิทธิขอคืน หลักประกันการรับเงินค่าจ้างล่วงหน้าบางส่วนก่อนได้')::character varying as d5_6_2,
		concat('(1) กรณีผู้รับจ้างวางหลักประกันการรับเงินค่าจ้างล่วงหน้าไว้ฉบับเดียว หากผู้ว่าจ้างได้หักเงินค่าจ้างล่วงหน้า ไปแล้ว ผู้รับจ้างมีสิทธิขอคืนหลักประกันการรับเงินค่าจ้างล่วงหน้า ในส่วนที่ผู้ว่าจ้างได้หักเงินค่าจ้างล่วงหน้าไปแล้วนั้น โดยผู้รับจ้างจะต้องนำ หลักประกันการรับเงินค่าจ้างล่วงหน้าฉบับใหม่ที่มีมูลค่าเท่ากับเงินค่าจ้างล่วงหน้าที่เหลืออยู่มาวางให้แก่ผู้ว่าจ้าง')::character varying as d5_6_2_1,
		concat('(2) กรณีผู้รับจ้างได้วางหลักประกันการรับเงินค่าจ้างล่วงหน้าไว้หลายฉบับ ซึ่งแต่ละฉบับมีมูลค่าเท่ากับ จำนวนเงินค่าจ้างล่วงหน้าที่ผู้ว่าจ้างจะต้องหักไว้ในแต่ละงวด หากผู้ว่าจ้างได้หักเงินค่าจ้างล่วงหน้าในงวดใดแล้ว ผู้รับจ้างมีสิทธิขอคืน หลักประกันการรับเงินค่าจ้างล่วงหน้าในงวดนั้นได้')::character varying as d5_6_2_2,
		concat('(18) ข้อ 6 การหักเงินประกันผลงาน')::character varying as d6,
		concat('ในการจ่ายเงินค่าจ้างให้แก่ผู้รับจ้างแต่ละงวด ผู้ว่าจ้างจะหักเงินจำนวนร้อยละ...................(…………………) ของเงินที่ต้องจ่ายในงวดนั้นเพื่อเป็นประกันผลงาน ในกรณีที่เงินประกันผลงาน ถูกหักไว้แล้วเป็นจำนวนเงินไม่ต่ำกว่า……….............บาท (……………………...) ผู้รับจ้างมีสิทธิที่จะ ขอเงินประกันผลงานคืน โดยนำหนังสือค้ำประกันของธนาคารหรือหนังสือค้ำประกันอิเล็กทรอนิกส์ ซึ่งออกโดยธนาคารภายในประเทศมามอบให้ผู้ว่าจ้างเพื่อเป็นหลักประกันแทนก็ได้')::character varying as d6_1,
		concat('ผู้ว่าจ้างจะคืนเงินประกันผลงาน และ/หรือหนังสือค้ำประกันของธนาคารดังกล่าว ตามวรรคหนึ่งโดยไม่มีดอกเบี้ยให้แก่ ผู้รับจ้างพร้อมกับการจ่ายเงินค่าจ้างงวดสุดท้าย')::character varying as d6_2,
		concat('ข้อ 7 (ก) กำหนดเวลาแล้วเสร็จและสิทธิของผู้ว่าจ้างในการบอกเลิกสัญญา')::character varying as d7_1,
		concat('(19) ภายในกำหนด………………......(.....................) วัน นับถัดจากวันลงนามในสัญญา ผู้รับจ้างจะต้องเสนอแผนงาน ให้เป็นที่พอใจแก่ผู้ว่าจ้าง โดยแสดงถึงขั้นตอนของการทำงานและกำหนดเวลา ที่ต้องใช้ในการทำงานหลักต่างๆ ให้แล้วเสร็จ')::character varying as d7_1_1,
		concat('ผู้รับจ้างต้องเริ่มทำงานที่รับจ้างภายในกำหนด…………....(...................) วัน นับถัดจากวันที่ได้รับหนังสือแจ้งให้เริ่มงาน และจะต้องทำงานให้แล้วเสร็จภายในกำหนด………………..(...................) วัน นับถัดจากวันที่ได้รับหนังสือแจ้งดังกล่าวนั้น')::character varying as d7_1_2,
		concat('ถ้าผู้รับจ้างมิได้เสนอแผนงาน หรือมิได้ลงมือทำงานภายในกำหนดเวลาหรือไม่สามารถทำงานให้แล้วเสร็จ ตามกำหนดเวลา หรือมีเหตุให้เชื่อได้ว่าผู้รับจ้างไม่สามารถทำงานให้แล้วเสร็จภายในกำหนดเวลา หรือจะแล้วเสร็จล่าช้าเกินกว่ากำหนดเวลา หรือผู้รับจ้างทำผิดสัญญาข้อใดข้อหนึ่ง หรือตกเป็นผู้ถูกพิทักษ์ทรัพย์เด็ดขาด หรือตกเป็นผู้ล้มละลาย หรือเพิกเฉยไม่ปฏิบัติตามคำสั่งของ คณะกรรมการตรวจรับพัสดุหรือผู้ควบคุมงานหรือบริษัทที่ปรึกษาซึ่งได้รับมอบอำนาจจากผู้ว่าจ้าง ผู้ว่าจ้างมีสิทธิที่จะ บอกเลิกสัญญานี้ได้ และมีสิทธิจ้างผู้รับจ้างรายใหม่เข้าทำงานของผู้รับจ้างให้ลุล่วงไปได้ด้วย การใช้สิทธิบอกเลิกสัญญานั้นไม่กระทบสิทธิของผู้ว่าจ้างที่จะ เรียกร้องค่าเสียหายจากผู้รับจ้าง')::character varying as d7_1_3,
		concat('การที่ผู้ว่าจ้างไม่ใช้สิทธิเลิกสัญญาดังกล่าวข้างต้นนั้น ไม่เป็นเหตุให้ผู้รับจ้างพ้นจากความรับผิดตามสัญญา')::character varying as d7_1_4,
		concat('ข้อ 7 (ข) กำหนดเวลาแล้วเสร็จและสิทธิของผู้ว่าจ้างในการบอกเลิกสัญญา')::character varying as d7_2,
		concat('ผู้รับจ้างต้องเริ่มทำงานที่รับจ้างภายใน',(select po_format_date_thai('วันที่','เดือน','พ.ศ.',a.start_con_date::date,p_lin_id )),' และจะต้องทำงานให้แล้วเสร็จ บริบูรณ์ภายใน',
				(select po_format_date_thai('วันที่','เดือน','พ.ศ.',a.end_con_date::date,p_lin_id )),
				' ถ้าผู้รับจ้างมิได้ลงมือทำงานภายในกำหนดเวลา หรือไม่สามารถทำงานให้แล้วเสร็จตาม กำหนดเวลา หรือมีเหตุให้เชื่อได้ว่า ผู้รับจ้างไม่สามารถทำงานให้แล้วเสร็จภายในกำหนดเวลา หรือจะแล้วเสร็จล่าช้าเกินกว่ากำหนดเวลาหรือ ผู้รับจ้างทำผิดสัญญาข้อใดข้อหนึ่ง หรือตกเป็นผู้ถูกพิทักษ์ทรัพย์เด็ดขาด หรือตกเป็นผู้ล้มละลาย หรือเพิกเฉยไม่ปฏิบัติตามคำสั่งของ คณะกรรมการตรวจรับพัสดุหรือผู้ควบคุมงานหรือบริษัทที่ปรึกษา ซึ่งได้รับมอบอำนาจจากผู้ว่าจ้าง ผู้ว่าจ้างมีสิทธิที่จะบอกเลิกสัญญานี้ได้ และมีสิทธิจ้างผู้รับจ้างรายใหม่ เข้าทำงานของผู้รับจ้างให้ลุล่วงไปด้วย การใช้สิทธิบอกเลิกสัญญานั้นไม่กระทบสิทธิของผู้ว่าจ้างที่จะเรียกร้อง ค่าเสียหายจากผู้รับจ้าง')::character varying as d7_2_1,
		concat('การที่ผู้ว่าจ้างไม่ใช้สิทธิเลิกสัญญาดังกล่าวข้างต้นไม่เป็นเหตุให้ผู้รับจ้างพ้นจากความรับผิดตามสัญญา')::character varying as d7_2_2,
		concat('ข้อ 8 ความรับผิดชอบในความชำรุดบกพร่องของงานจ้าง')::character varying as d8,
		concat('เมื่องานแล้วเสร็จบริบูรณ์ และผู้ว่าจ้างได้รับมอบงานจากผู้รับจ้างหรือจากผู้รับจ้างรายใหม่ ในกรณีที่มีการ บอกเลิกสัญญาตามข้อ 7 หากมีเหตุชำรุดบกพร่องหรือเสียหายเกิดขึ้นจากการจ้างนี้ ภายในกำหนด.......(20)..…..(……..….…..) ปี …….… (………....….) เดือน นับถัดจากวันที่ได้รับมอบงานดังกล่าว ซึ่งความชำรุดบกพร่องหรือเสียหายนั้นเกิดจากความบกพร่องของผู้รับจ้าง อันเกิดจากการใช้วัสดุที่ไม่ถูกต้องหรือทำไว้ไม่เรียบร้อย หรือทำไม่ถูกต้องตามมาตรฐานแห่งหลักวิชา ผู้รับจ้างจะต้องรีบทำการแก้ไข ให้เป็นที่เรียบร้อยโดยไม่ชักช้า โดยผู้ว่าจ้างไม่ต้องออกเงินใด ๆ ในการนี้ทั้งสิ้น หากผู้รับจ้าง ไม่กระทำการดังกล่าวภายในกำหนด ',
				a.complete_day,' '
				'( ',po_qty_text(a.complete_day::numeric),' )',
				' วัน ','นับถัดจากวันที่ได้รับแจ้งเป็นหนังสือจากผู้ว่าจ้างหรือไม่ทำการแก้ไขให้ถูกต้องเรียบร้อยภายในเวลาที่ผู้ว่าจ้างกำหนด ให้ผู้ว่าจ้างมีสิทธิที่จะทำการนั้นเอง หรือจ้างผู้อื่นให้ทำงานนั้น โดยผู้รับจ้างต้องเป็นผู้ออกค่าใช้จ่ายเองทั้งสิ้น')::character varying as d8_1,
		concat('ในกรณีเร่งด่วนจำเป็นต้องรีบแก้ไขเหตุชำรุดบกพร่องหรือเสียหายโดยเร็ว และไม่อาจรอให้ผู้รับจ้างแก้ไขในระยะเวลา ที่กำหนดไว้ตามวรรคหนึ่งได้ ผู้ว่าจ้างมีสิทธิเข้าจัดการแก้ไขเหตุชำรุดบกพร่องหรือเสียหายนั้นเอง หรือจ้างผู้อื่นให้ซ่อมแซมความชำรุดบกพร่อง หรือเสียหาย โดยผู้รับจ้าง ต้องรับผิดชอบชำระค่าใช้จ่ายทั้งหมด')::character varying as d8_2,
		concat('การที่ผู้ว่าจ้างทำการนั้นเอง หรือจ้างผู้อื่นให้ทำงานนั้นแทนผู้รับจ้าง ไม่ทำให้ผู้รับจ้าง หลุดพ้นจากความรับผิดตามสัญญา หากผู้รับจ้างไม่ชดใช้ค่าใช้จ่ายหรือค่าเสียหายตามที่ผู้ว่าจ้างเรียกร้องผู้ว่าจ้างมีสิทธิบังคับจากหลักประกันการปฏิบัติตามสัญญาได้')::character varying as d8_3,
		concat('ข้อ 9 การจ้างช่วง')::character varying as d9,
		concat('ผู้รับจ้างจะต้องไม่เอางานทั้งหมดหรือแต่บางส่วนแห่งสัญญานี้ไปจ้างช่วงอีกทอดหนึ่ง เว้นแต่การจ้างช่วงงานแต่บางส่วน ที่ได้รับอนุญาตเป็นหนังสือจากผู้ว่าจ้างแล้วการที่ผู้ว่าจ้างได้อนุญาต ให้จ้างช่วงงานแต่บางส่วนดังกล่าวนั้นไม่เป็นเหตุให้ผู้รับจ้างหลุดพ้น จากความรับผิดหรือพันธะหน้าที่ ตามสัญญานี้ และผู้รับจ้างจะยังคงต้องรับผิดในความผิดและความประมาทเลินเล่อของผู้รับจ้างช่วง หรือของตัวแทนหรือลูกจ้างของผู้รับจ้างช่วงนั้นทุกประการ')::character varying as d9_1,
		concat('กรณีผู้รับจ้างไปจ้างช่วงงานแต่บางส่วนโดยฝ่าฝืนความในวรรคหนึ่ง ผู้รับจ้าง ต้องชำระค่าปรับให้แก่ผู้ว่าจ้าง เป็นจำนวนเงินในอัตราร้อยละ ',
				TO_CHAR(a.fine_rate::numeric, 'FM999G999G999D00')::numeric,
					' ( ',po_read_number_digit_text(a.fine_rate),' ) ','ของวงเงินของงานที่จ้างช่วงตามสัญญา ทั้งนี้ไม่ตัดสิทธิผู้ว่าจ้าง ในการบอกเลิกสัญญา')::character varying as d9_2,
		concat('ข้อ 10 การควบคุมงานของผู้รับจ้าง')::character varying as d10,
		concat('ผู้รับจ้างจะต้องควบคุมงานที่รับจ้างอย่างเอาใจใส่ ด้วยประสิทธิภาพและความชำนาญและในระหว่างทำงานที่รับจ้าง จะต้องจัดให้มีผู้แทนซึ่งทำงานเต็มเวลาเป็นผู้รับผิดชอบควบคุมงาน ของผู้รับจ้าง ผู้แทนดังกล่าวจะต้องได้รับมอบอำนาจจากผู้รับจ้าง คำสั่ง หรือคำแนะนำต่างๆ ที่ผู้ว่าจ้าง คณะกรรมการตรวจรับพัสดุ ผู้ควบคุมงาน หรือบริษัทที่ปรึกษาที่ผู้ว่าจ้างแต่งตั้งได้แจ้งแก่ผู้แทนเช่นว่านั้น ให้ถือว่าเป็นคำสั่งหรือคำแนะนำที่ได้แจ้งแก่ผู้รับจ้าง การแต่งตั้งผู้แทนตามข้อนี้จะต้องทำเป็นหนังสือ และต้องได้รับความเห็นชอบเป็นหนังสือ จากผู้ว่าจ้าง การเปลี่ยนตัวหรือแต่งตั้งผู้แทนใหม่จะทำมิได้ หากไม่ได้รับความเห็นชอบเป็นหนังสือจากผู้ว่าจ้างก่อน')::character varying as d10_1,
		concat('ผู้ว่าจ้างมีสิทธิที่จะขอให้เปลี่ยนตัวผู้แทนตามวรรคหนึ่ง โดยแจ้งเป็นหนังสือไปยัง ผู้รับจ้าง และผู้รับจ้างจะต้องทำการ เปลี่ยนตัวผู้แทนนั้นโดยพลัน โดยไม่คิดค่าจ้างหรือราคาเพิ่ม หรืออ้างเป็นเหตุเพื่อขยายอายุสัญญาอันเนื่องมาจากเหตุนี้')::character varying as d10_2,
		concat('ข้อ 11 ความรับผิดของผู้รับจ้าง')::character varying as d11,
		concat('ผู้รับจ้างจะต้องรับผิดต่ออุบัติเหตุ ความเสียหาย หรือภยันตรายใดๆ อันเกิดจาก การปฏิบัติงานของผู้รับจ้าง และจะต้องรับผิดต่อความเสียหายจากการกระทำของลูกจ้างหรือตัวแทน ของผู้รับจ้าง และจากการปฏิบัติงานของผู้รับจ้างช่วงด้วย (ถ้ามี)')::character varying as d11_1,
		concat('ความเสียหายใด ๆ อันเกิดแก่งานที่ผู้รับจ้างได้ทำขึ้น แม้จะเกิดขึ้นเพราะเหตุสุดวิสัย ก็ตาม ผู้รับจ้างจะต้องรับผิดชอบ โดยซ่อมแซมให้คืนดีหรือเปลี่ยนให้ใหม่โดยค่าใช้จ่ายของผู้รับจ้างเอง เว้นแต่ความเสียหายนั้นเกิดจากความผิดของผู้ว่าจ้าง ทั้งนี้ความรับผิด ของผู้รับจ้างดังกล่าวในข้อนี้จะสิ้นสุดลง  เมื่อผู้ว่าจ้างได้รับมอบงานครั้งสุดท้าย ซึ่งหลังจากนั้นผู้รับจ้างคงต้องรับผิดเพียงในกรณีชำรุดบกพร่อง หรือความเสียหายดังกล่าวในข้อ 8 เท่านั้น')::character varying as d11_2,
		concat('ผู้รับจ้างจะต้องรับผิดต่อบุคคลภายนอกในความเสียหายใดๆ อันเกิดจากการปฏิบัติงานของผู้รับจ้าง หรือลูกจ้างหรือ ตัวแทนของผู้รับจ้าง รวมถึงผู้รับจ้างช่วง (ถ้ามี) ตามสัญญานี้ หากผู้ว่าจ้าง ถูกเรียกร้องหรือฟ้องร้องหรือต้องชดใช้ค่าเสียหายให้แก่ บุคคลภายนอกไปแล้ว ผู้รับจ้างจะต้องดำเนินการใด ๆ เพื่อให้มีการว่าต่างแก้ต่างให้แก่ผู้ว่าจ้างโดยค่าใช้จ่ายของผู้รับจ้างเอง รวมทั้งผู้รับจ้าง จะต้องชดใช้ค่าเสียหายนั้น ๆ ตลอดจนค่าใช้จ่ายใด ๆ อันเกิดจากการถูกเรียกร้องหรือถูกฟ้องร้องให้แก่ผู้ว่าจ้างทันที')::character varying as d11_3,
		concat('ข้อ 12 การจ่ายเงินแก่ลูกจ้าง')::character varying as d12,
		concat('ผู้รับจ้างจะต้องจ่ายเงินแก่ลูกจ้างที่ผู้รับจ้างได้จ้างมาในอัตราและตามกำหนดเวลาที่ผู้รับจ้างได้ตกลง หรือทำสัญญาไว้ ต่อลูกจ้างดังกล่าว')::character varying as d12_1,
		concat('ถ้าผู้รับจ้างไม่จ่ายเงินค่าจ้างหรือค่าทดแทนอื่นใดแก่ลูกจ้างดังกล่าวในวรรคหนึ่ง ผู้ว่าจ้างมีสิทธิที่จะเอาเงินค่าจ้าง ที่จะต้องจ่ายแก่ผู้รับจ้างมาจ่ายให้แก่ลูกจ้างของผู้รับจ้างดังกล่าว และให้ถือว่าผู้ว่าจ้างได้จ่ายเงินจำนวนนั้นเป็นค่าจ้างให้แก่ผู้รับจ้าง ตามสัญญาแล้ว')::character varying as d12_2,
		concat('ผู้รับจ้างจะต้องจัดให้มีประกันภัยสำหรับลูกจ้างทุกคนที่จ้างมาทำงาน โดยให้ครอบคลุมถึงความรับผิดทั้งปวงของ ผู้รับจ้าง รวมทั้งผู้รับจ้างช่วง (ถ้ามี) ในกรณีความเสียหายที่คิดค่าสินไหมทดแทน ได้ตามกฎหมาย ซึ่งเกิดจากอุบัติเหตุหรือภยันตรายใด ๆ ต่อลูกจ้างหรือบุคคลอื่นที่ผู้รับจ้าง หรือผู้รับจ้างช่วงจ้างมาทำงาน ผู้รับจ้างจะต้องส่งมอบกรมธรรม์ประกันภัยดังกล่าวพร้อมทั้งหลักฐาน การชำระเบี้ยประกันให้แก่ผู้ว่าจ้างเมื่อผู้ว่าจ้างเรียกร้อง')::character varying as d12_3,
		concat('ข้อ 13 การตรวจงานจ้าง')::character varying as d13,
		concat('ถ้าผู้ว่าจ้างแต่งตั้งคณะกรรมการตรวจรับพัสดุ ผู้ควบคุมงาน หรือบริษัทที่ปรึกษา เพื่อควบคุมการทำงานของผู้รับจ้าง คณะกรรมการตรวจรับพัสดุ ผู้ควบคุมงาน หรือบริษัทที่ปรึกษานั้น มีอำนาจเข้าไปตรวจการงานในโรงงานและสถานที่ก่อสร้างได้ทุกเวลา และผู้รับจ้างจะต้องอำนวย ความสะดวกและให้ความช่วยเหลือในการนั้นตามสมควร')::character varying as d13_1,
		concat('การที่มีคณะกรรมการตรวจรับพัสดุ ผู้ควบคุมงาน หรือบริษัทที่ปรึกษานั้น หาทำให้ผู้รับจ้างพ้นความรับผิดชอบ ตามสัญญานี้ข้อใดข้อหนึ่งไม่')::character varying as d13_2,
		concat('ข้อ 14 แบบรูปและรายการละเอียดคลาดเคลื่อน')::character varying as d14,
		concat('ผู้รับจ้างรับรองว่าได้ตรวจสอบและทำความเข้าใจในแบบรูปและรายการละเอียด โดยถี่ถ้วนแล้ว หากปรากฏว่าแบบรูป และรายการละเอียดนั้นผิดพลาดหรือคลาดเคลื่อนไปจากหลักการ ทางวิศวกรรมหรือทางเทคนิค ผู้รับจ้างตกลงที่จะปฏิบัติตามคำวินิจฉัย ของผู้ว่าจ้าง คณะกรรมการตรวจรับพัสดุ ผู้ควบคุมงาน หรือบริษัทที่ปรึกษาที่ผู้ว่าจ้างแต่งตั้ง เพื่อให้งานแล้วเสร็จบริบูรณ์ คำวินิจฉัยดังกล่าว ให้ถือเป็นที่สุด โดยผู้รับจ้างจะคิดค่าจ้าง ค่าเสียหาย หรือค่าใช้จ่ายใด ๆ เพิ่มขึ้นจากผู้ว่าจ้าง หรือขอขยายอายุสัญญาไม่ได้')::character varying as d14_1,
		concat('ข้อ 15 การควบคุมงานโดยผู้ว่าจ้าง')::character varying as d15,
		concat('ผู้รับจ้างตกลงว่าคณะกรรมการตรวจรับพัสดุ ผู้ควบคุมงาน หรือบริษัทที่ปรึกษา ที่ผู้ว่าจ้างแต่งตั้ง มีอำนาจที่จะ ตรวจสอบและควบคุมงานเพื่อให้เป็นไปตามสัญญานี้และมีอำนาจที่จะสั่งให้แก้ไขเปลี่ยนแปลงเพิ่มเติม หรือตัดทอนซึ่งงานตามสัญญานี้หาก ผู้รับจ้างขัดขืนไม่ปฏิบัติตาม ผู้ว่าจ้าง คณะกรรมการตรวจรับพัสดุ ผู้ควบคุมงาน หรือบริษัทที่ปรึกษา มีอำนาจที่จะสั่งให้หยุดการนั้นชั่วคราว ได้ ความล่าช้าในกรณีเช่นนี้ ผู้รับจ้างจะถือเป็นเหตุขอขยายระยะเวลาการปฏิบัติงานตามสัญญาหรือเรียกร้องค่าเสียหายใด ๆ ไม่ได้ทั้งสิ้น')::character varying as d15_1,
		concat('ข้อ 16 งานพิเศษและการแก้ไขงาน')::character varying as d16,
		concat('ผู้ว่าจ้างมีสิทธิที่จะสั่งเป็นหนังสือให้ผู้รับจ้างทำงานพิเศษซึ่งไม่ได้แสดงไว้หรือรวมอยู่ในเอกสารสัญญานี้ หากงานพิเศษนั้นๆ อยู่ในขอบข่ายทั่วไปแห่งวัตถุประสงค์ของสัญญานี้ นอกจากนี้ ผู้ว่าจ้างยังมีสิทธิสั่งให้เปลี่ยนแปลงหรือแก้ไขแบบรูป และข้อกำหนดต่าง ๆ ในเอกสารสัญญานี้ด้วย อัตราค่าจ้างหรือราคาที่กำหนดไว้ในสัญญานี้ ให้กำหนดใช้สำหรับงานพิเศษหรืองานที่เพิ่มเติมขึ้น  หรือตัดทอนลงทั้งปวงตามคำสั่งของผู้ว่าจ้าง หากในสัญญาไม่ได้กำหนดไว้ถึง อัตราค่าจ้าง หรือราคาใด ๆ ที่จะนำมาใช้สำหรับงานพิเศษหรือ งานที่เพิ่มขึ้นหรือลดลงดังกล่าว ผู้ว่าจ้าง และผู้รับจ้างจะได้ตกลงกันที่จะกำหนดอัตราค่าจ้างหรือราคาที่เพิ่มขึ้นหรือลดลง รวมทั้งการขยาย ระยะเวลา (ถ้ามี) กันใหม่เพื่อความเหมาะสม ในกรณีที่ตกลงกันไม่ได้ ผู้ว่าจ้างจะกำหนดอัตราจ้างหรือราคาตามแต่ผู้ว่าจ้างจะเห็นว่าเหมาะสม และถูกต้อง ซึ่งผู้รับจ้างจะต้องปฏิบัติงานตามคำสั่งของผู้ว่าจ้างไปก่อนเพื่อมิให้เกิดความเสียหายแก่งานที่จ้าง')::character varying as d16_1,
		concat('ข้อ 17 ค่าปรับ')::character varying as d17,
		concat('หากผู้รับจ้างไม่สามารถทำงานให้แล้วเสร็จภายในเวลาที่กำหนดไว้ในสัญญา และผู้ว่าจ้างยังมิได้บอกเลิกสัญญา ผู้รับจ้างจะต้องชำระค่าปรับให้แก่ผู้ว่าจ้างเป็นจำนวนเงินวันละ …........(22)……..….บาท (……...................………...) และจะต้องชำระค่าใช้จ่าย ในการควบคุมงาน (ถ้ามี) ในเมื่อผู้ว่าจ้างต้องจ้างผู้ควบคุมงานอีกต่อหนึ่งเป็นจำนวนเงินวันละ…....(23)….....บาท (…..................) นับถัดจากวันที่ครบกำหนดเวลาแล้วเสร็จของงานตามสัญญาหรือวันที่ผู้ว่าจ้างได้ขยายเวลาทำงานให้ จนถึงวันที่ทำงานแล้วเสร็จจริง นอกจากนี้ ผู้รับจ้างยอมให้ผู้ว่าจ้างเรียกค่าเสียหายอันเกิดขึ้นจากการที่   ผู้รับจ้างทำงานล่าช้าเฉพาะส่วนที่เกินกว่าจำนวนค่าปรับและ ค่าใช้จ่ายดังกล่าวได้อีกด้วย')::character varying as d17_1,
		concat('ในระหว่างที่ผู้ว่าจ้างยังมิได้บอกเลิกสัญญานั้น หากผู้ว่าจ้างเห็นว่าผู้รับจ้างจะไม่สามารถปฏิบัติตามสัญญาต่อไปได้ ผู้ว่าจ้างจะใช้สิทธิบอกเลิกสัญญาและใช้สิทธิตามข้อ 18 ก็ได้ และถ้าผู้ว่าจ้าง ได้แจ้งข้อเรียกร้องไปยังผู้รับจ้างเมื่อครบกำหนดเวลา แล้วเสร็จของงานขอให้ชำระค่าปรับแล้ว ผู้ว่าจ้างมีสิทธิ  ที่จะปรับผู้รับจ้างจนถึงวันบอกเลิกสัญญาได้อีกด้วย')::character varying as d17_2,
		concat('ข้อ 18 สิทธิของผู้ว่าจ้างภายหลังบอกเลิกสัญญา')::character varying as d18,
		concat('ในกรณีที่ผู้ว่าจ้างบอกเลิกสัญญา ผู้ว่าจ้างอาจทำงานนั้นเองหรือว่าจ้างผู้อื่นให้ทำงานนั้นต่อจนแล้วเสร็จก็ได้ ผู้ว่าจ้างหรือผู้ที่รับจ้างทำงานนั้นต่อมีสิทธิใช้เครื่องใช้ในการก่อสร้าง สิ่งที่สร้างขึ้นชั่วคราวสำหรับงานก่อสร้างและวัสดุต่าง ๆ ซึ่งเห็นว่าจะต้องสงวนเอาไว้เพื่อการปฏิบัติงานตามสัญญา ตามที่จะเห็นสมควร')::character varying as d18_1,
		concat('ในกรณีดังกล่าว ผู้ว่าจ้างมีสิทธิริบหรือบังคับจากหลักประกันการปฏิบัติตามสัญญา ทั้งหมดหรือบางส่วนตามแต่จะ เห็นสมควร นอกจากนั้น ผู้รับจ้างจะต้องรับผิดชอบในค่าเสียหายซึ่งเป็นจำนวนเกินกว่าหลักประกันการปฏิบัติตามสัญญา รวมทั้งค่าใช้จ่าย ที่เพิ่มขึ้นในการทำงานนั้นต่อให้แล้วเสร็จตามสัญญา ตลอดจนค่าใช้จ่ายในการควบคุมงานเพิ่ม (ถ้ามี) ซึ่งผู้ว่าจ้างจะหักเอาจากเงินประกัน ผลงานหรือจำนวนเงินใด ๆ ที่จะจ่ายให้แก่ผู้รับจ้างก็ได้')::character varying as d18_2,
		concat('ข้อ 19 การบังคับค่าปรับ ค่าเสียหาย และค่าใช้จ่าย')::character varying as d19,
		concat('ในกรณีที่ผู้รับจ้างไม่ปฏิบัติตามสัญญาข้อใดข้อหนึ่งด้วยเหตุใด ๆ ก็ตาม จนเป็นเหตุ ให้เกิดค่าปรับ ค่าเสียหาย หรือค่าใช้จ่ายแก่ผู้ว่าจ้าง ผู้รับจ้างต้องชดใช้ค่าปรับ ค่าเสียหาย หรือค่าใช้จ่ายดังกล่าวให้แก่ผู้ว่าจ้างโดยสิ้นเชิงภายในกำหนด .................... (.....................) วัน นับถัดจากวันที่ได้รับแจ้ง เป็นหนังสือจากผู้ว่าจ้าง หากผู้รับจ้างไม่ชดใช้ให้ถูกต้องครบถ้วนภายในระยะเวลาดังกล่าวให้ ผู้ว่าจ้างมีสิทธิที่จะหักเอาจากจำนวนเงินค่าจ้างที่ต้องชำระ หรือจากเงินประกันผลงานของผู้รับจ้าง หรือบังคับจากหลักประกันการปฏิบัติ ตามสัญญาได้ทันที')::character varying as d19_1,
		concat('หากค่าปรับ ค่าเสียหาย หรือค่าใช้จ่ายที่บังคับจากเงินค่าจ้างที่ต้องชำระ เงินประกันผลงานหรือหลักประกัน การปฏิบัติตามสัญญาแล้วยังไม่เพียงพอ ผู้รับจ้างยินยอมชำระส่วนที่เหลือที่ยังขาดอยู่จนครบถ้วนตามจำนวนค่าปรับ ค่าเสียหาย หรือค่าใช้จ่ายนั้น ภายในกำหนด..................(......................) วัน นับถัดจากวันที่ได้รับแจ้งเป็นหนังสือจากผู้ว่าจ้าง')::character varying as d19_2,
		concat('หากมีเงินค่าจ้างตามสัญญาที่หักไว้จ่ายเป็นค่าปรับ ค่าเสียหาย หรือค่าใช้จ่ายแล้ว ยังเหลืออยู่อีกเท่าใด ผู้ว่าจ้างจะคืนให้แก่ผู้รับจ้างทั้งหมด')::character varying as d19_3,
		concat('ข้อ 20 การทำบริเวณก่อสร้างให้เรียบร้อย')::character varying as d20,
		concat('ผู้รับจ้างจะต้องรักษาบริเวณสถานที่ปฏิบัติงานตามสัญญานี้ รวมทั้งโรงงานหรือ สิ่งอำนวยความสะดวกในการทำงาน ของผู้รับจ้าง ลูกจ้าง ตัวแทน หรือผู้รับจ้างช่วง (ถ้ามี) ให้สะอาด ปลอดภัย และมีประสิทธิภาพในการใช้งานตลอดระยะเวลาการจ้าง และเมื่อทำงานเสร็จสิ้นแล้วจะต้องขนย้าย บรรดาเครื่องใช้ในการทำงานจ้างรวมทั้งวัสดุ ขยะมูลฝอย และสิ่งก่อสร้างชั่วคราวต่างๆ (ถ้ามี) ทั้งจะต้อง กลบเกลี่ยพื้นดินให้เรียบร้อยเพื่อให้บริเวณทั้งหมดอยู่ในสภาพที่สะอาดและใช้การได้ทันที')::character varying as d20_1,
		concat('ข้อ 21 การงดหรือลดค่าปรับ หรือการขยายเวลาปฏิบัติงานตามสัญญา')::character varying as d21,
		concat('ในกรณีที่มีเหตุเกิดจากความผิดหรือความบกพร่องของฝ่ายผู้ว่าจ้าง หรือเหตุสุดวิสัย หรือเกิดจากพฤติการณ์ อันหนึ่งอันใดที่ผู้รับจ้างไม่ต้องรับผิดตามกฎหมาย หรือเหตุอื่นตามที่กำหนด ในกฎกระทรวง ซึ่งออกตามความในกฎหมายว่าด้วยการ จัดซื้อจัดจ้างและการบริหารพัสดุภาครัฐ ทำให้ ผู้รับจ้างไม่สามารถทำงานให้แล้วเสร็จตามเงื่อนไขและกำหนดเวลาแห่งสัญญานี้ได้ ผู้รับจ้างจะต้องแจ้งเหตุหรือพฤติการณ์ดังกล่าวพร้อมหลักฐานเป็นหนังสือให้ผู้ว่าจ้างทราบ เพื่อของดหรือลดค่าปรับ หรือขยายเวลาทำงานออกไปภายใน 15 (สิบห้า) วัน นับถัดจากวันที่เหตุนั้นสิ้นสุดลง หรือตามที่กำหนดในกฎกระทรวงดังกล่าว แล้วแต่กรณี')::character varying as d21_1,
		concat('ถ้าผู้รับจ้างไม่ปฏิบัติให้เป็นไปตามความในวรรคหนึ่ง ให้ถือว่าผู้รับจ้างได้สละสิทธิเรียกร้องในการที่จะของด หรือลดค่าปรับ หรือขยายเวลาทำงานออกไปโดยไม่มีเงื่อนไขใด ๆ ทั้งสิ้น เว้นแต่ กรณีเหตุเกิดจากความผิดหรือความบกพร่องของ ฝ่ายผู้ว่าจ้างซึ่งมีหลักฐานชัดแจ้งหรือผู้ว่าจ้างทราบดีอยู่แล้วตั้งแต่ต้น')::character varying as d21_2,
		concat('การงดหรือลดค่าปรับ หรือขยายกำหนดเวลาทำงานตามวรรคหนึ่ง อยู่ในดุลพินิจของผู้ว่าจ้างที่จะพิจารณา ตามที่เห็นสมควร')::character varying as d21_3,
		concat('(24) ข้อ 22 การใช้เรือไทย')::character varying as d22,
		concat('ในการปฏิบัติตามสัญญานี้ หากผู้รับจ้างจะต้องสั่งหรือนำของเข้ามาจากต่างประเทศรวมทั้งเครื่องมือและอุปกรณ์ที่ต้อง นำเข้ามาเพื่อปฏิบัติงานตามสัญญา ไม่ว่าผู้รับจ้างจะเป็นผู้ที่นำของเข้ามาเองหรือนำเข้ามาโดยผ่านตัวแทนหรือบุคคลอื่นใด ถ้าสิ่งของนั้นต้อง นำเข้ามาโดยทางเรือในเส้นทางเดินเรือ ที่มีเรือไทยเดินอยู่และสามารถให้บริการรับขนได้ตามที่ รัฐมนตรีว่าการกระทรวงคมนาคมประกาศ กำหนดผู้รับจ้างต้องจัดการให้สิ่งของดังกล่าวบรรทุกโดยเรือไทยหรือเรือที่มีสิทธิเช่นเดียวกับ เรือไทยจากต่างประเทศมายังประเทศไทย เว้นแต่จะได้รับอนุญาตจากกรมเจ้าท่าก่อนบรรทุกของนั้นลงเรืออื่นที่มิใช่เรือไทยหรือเป็นของที่รัฐมนตรีว่าการกระทรวงคมนาคม ประกาศยกเว้นให้บรรทุกโดยเรืออื่นได้ ทั้งนี้ไม่ว่าการสั่งหรือนำเข้าสิ่งของดังกล่าวจาก ต่างประเทศจะเป็นแบบใด')::character varying as d22_1,
		concat('ในการส่งมอบงานตามสัญญาให้แก่ผู้ว่าจ้าง ถ้างานนั้นมีสิ่งของตามวรรคหนึ่ง ผู้รับจ้างจะต้องส่งมอบใบตราส่ง (Bill of Lading) หรือสำเนาใบตราส่งสำหรับของนั้น ซึ่งแสดงว่าได้บรรทุกมาโดยเรือไทยหรือเรือที่มีสิทธิเช่นเดียวกับเรือไทยให้แก่ผู้ว่าจ้างพร้อมกับ การส่งมอบงานด้วย')::character varying as d22_2,
		concat('ในกรณีที่สิ่งของดังกล่าวไม่ได้บรรทุกจากต่างประเทศมายังประเทศไทยโดยเรือไทยหรือเรือที่มีสิทธิเช่นเดียวกับเรือไทย ผู้รับจ้างต้องส่งมอบหลักฐานซึ่งแสดงว่าได้รับอนุญาตจากกรมเจ้าท่าให้บรรทุกของโดยเรืออื่นได้หรือหลักฐานซึ่งแสดงว่าได้ชำระค่าธรรมเนียม พิเศษเนื่องจากการไม่บรรทุกของโดยเรือไทยตามกฎหมายว่าด้วยการส่งเสริมการพาณิชยนาวีแล้วอย่างใดอย่างหนึ่งแก่ผู้ว่าจ้างด้วย')::character varying as d22_3,
		concat('ในกรณีที่ผู้รับจ้างไม่ส่งมอบหลักฐานอย่างใดอย่างหนึ่งดังกล่าวในวรรคสองและวรรคสามให้แก่ผู้ว่าจ้าง แต่จะขอส่งมอบ งานดังกล่าวให้ผู้ว่าจ้างก่อนโดยไม่รับชำระเงินค่าจ้าง ผู้ว่าจ้างมีสิทธิรับงานดังกล่าวไว้ก่อน และชำระเงินค่าจ้างเมื่อผู้รับจ้างได้ปฏิบัติถูกต้อง ครบถ้วนดังกล่าวแล้วได้')::character varying as d22_4,
		concat('ข้อ 23 มาตรฐานฝีมือช่าง')::character varying as d23,
		concat('ผู้รับจ้างตกลงเป็นเงื่อนไขสำคัญว่า ผู้รับจ้างจะต้องมีและใช้ผู้ผ่านการทดสอบมาตรฐานฝีมือช่าง จาก ........................................................... หรือผู้มีวุฒิบัตรระดับ ปวช. ปวส. หรือ ปวท. หรือเทียบเท่าจากสถาบันการศึกษาที่ ก.พ. รับรองให้เข้ารับราชการได้ ในอัตราไม่ต่ำกว่าร้อยละ……(……..) ของแต่ละสาขาช่าง แต่จะต้องมีช่างจำนวนอย่างน้อย 1 (หนึ่ง) คน ในแต่ละสาขาช่างดังต่อไปนี้')::character varying as d23_0,
		concat('23.1 ………………………………………………….............................')::character varying as d23_1,
		concat('23.2 ………………………………………………….............................')::character varying as d23_2,
		concat('…….…………………………..ฯลฯ.…….…………………………..')::character varying as d23_f,
		concat('ผู้รับจ้างจะต้องจัดทำบัญชีแสดงจำนวนช่างทั้งหมดโดยจำแนกตามแต่ละสาขาช่าง และระดับช่าง พร้อมกับระบุรายชื่อช่างผู้ที่ผ่านการทดสอบมาตรฐานฝีมือช่างหรือผู้มีวุฒิบัตรดังกล่าว ในวรรคหนึ่ง นำมาแสดงพร้อมหลักฐานต่าง ๆ ต่อคณะกรรมการตรวจรับพัสดุ หรือผู้ควบคุมงานก่อนเริ่มลงมือทำงาน และพร้อมที่จะให้ผู้ว่าจ้างหรือเจ้าหน้าที่ของผู้ว่าจ้างตรวจสอบดูได้ตลอดเวลาทำงานตามสัญญานี้ของผู้รับจ้าง')::character varying as d23_f1,
		concat('สัญญานี้ทำขึ้นเป็นสองฉบับ มีข้อความถูกต้องตรงกัน คู่สัญญาได้อ่านและเข้าใจข้อความ โดยละเอียดตลอดแล้ว จึงได้ลงลายมือชื่อ พร้อมทั้งประทับตรา (ถ้ามี) ไว้เป็นสำคัญต่อหน้าพยาน และคู่สัญญาต่างยึดถือไว้ฝ่ายละหนึ่งฉบับ')::character varying as d23_f2,
        concat('(ลงชื่อ) ',deapprove.emp_name,' ผู้ว่าจ้าง')::character varying as sys1,
        concat('( ',a.sign_posi,' ',a.approve_posi,' )')::character varying as sys2,
        concat('(ลงชื่อ)…………..........……………..ผู้รับจ้าง')::character varying as sys3,
        concat('(…………………………….…)')::character varying as sys4,
        concat('(ลงชื่อ)…………..........……………..พยาน')::character varying as sys5,
        concat('(…………………………….…)')::character varying as sys6,
        concat('(ลงชื่อ)…………..........……………..พยาน')::character varying as sys7,
        concat('(…………………………….…)')::character varying as sys8,
        concat('วิธีปฏิบัติเกี่ยวกับสัญญาจ้างก่อสร้าง')::character varying as f0,
        concat('(1) ให้ระบุเลขที่สัญญาในปีงบประมาณหนึ่งๆ ตามลำดับ')::character varying as f1,
        concat('(2) ให้ระบุชื่อของหน่วยงานของรัฐที่เป็นนิติบุคคล เช่น กรม ก. หรือรัฐวิสาหกิจ ข. เป็นต้น')::character varying as f2,
        concat('(3) ให้ระบุชื่อและตำแหน่งของหัวหน้าหน่วยงานของรัฐที่เป็นนิติบุคคลนั้น หรือผู้ที่ได้รับมอบอำนาจ เช่น นาย ก. อธิบดีกรม……………...หรือ นาย ข. ผู้ได้รับมอบอำนาจจากอธิบดีกรม………………..')::character varying as f3,
        concat('(4) ให้ระบุชื่อผู้รับจ้าง')::character varying as f4,
        concat('ก. กรณีนิติบุคคล เช่น ห้างหุ้นส่วนสามัญจดทะเบียน ห้างหุ้นส่วนจำกัด บริษัทจำกัด')::character varying as f4_1,
        concat('ข. กรณีบุคคลธรรมดา ให้ระบุชื่อและที่อยู่')::character varying as f4_2,
        concat('(5) เป็นข้อความหรือเงื่อนไขเพิ่มเติม ซึ่งหน่วยงานของรัฐผู้ทำสัญญาอาจเลือกใช้หรือตัดออกได้ตามข้อเท็จจริง')::character varying as f5,
        concat('(6) เป็นข้อความหรือเงื่อนไขเพิ่มเติม ซึ่งหน่วยงานของรัฐผู้ทำสัญญาอาจเลือกใช้หรือตัดออกได้ตามข้อเท็จจริง')::character varying as f6,
        concat('(7) ให้ระบุงานที่ต้องการจ้าง')::character varying as f7,
        concat('(8) “หลักประกัน” หมายถึง หลักประกันที่ผู้รับจ้างนำมามอบไว้แก่หน่วยงานของรัฐเมื่อลงนามในสัญญา เพื่อเป็นการประกันความเสียหายที่อาจจะเกิดขึ้นจากการปฏิบัติตามสัญญา ดังนี้')::character varying as f8,
        concat('(1) เงินสด')::character varying as f8_1,
        concat('(2) เช็คหรือดราฟท์ที่ธนาคารเซ็นสั่งจ่าย ซึ่งเป็นเช็คหรือดราฟท์ลงวันที่ที่ใช้เช็ค หรือดราฟท์นั้นชำระต่อเจ้าหน้าที่ หรือก่อนวันนั้นไม่เกิน 3 วันทำการ')::character varying as f8_2,
        concat('(3) หนังสือค้ำประกันของธนาคารภายในประเทศตามตัวอย่างที่คณะกรรมการนโยบายกำหนด โดยอาจเป็นหนังสือค้ำประกันอิเล็กทรอนิกส์ตามวิธีการที่กรมบัญชีกลางกำหนดก็ได้')::character varying as f8_3,
        concat('(4) หนังสือค้ำประกันของบริษัทเงินทุนหรือบริษัทเงินทุนหลักทรัพย์ที่ได้รับอนุญาตให้ประกอบกิจการเงินทุน เพื่อการพาณิชย์และประกอบธุรกิจค้ำประกันตามประกาศของธนาคาร แห่งประเทศไทย ตามรายชื่อบริษัทเงินทุนที่ธนาคารแห่งประเทศไทย แจ้งเวียนให้ทราบ โดยอนุโลม ให้ใช้ตามตัวอย่างหนังสือค้ำประกันของธนาคารที่คณะกรรมการนโยบายกำหนด')::character varying as f8_4,
        concat('(5) พันธบัตรรัฐบาลไทย')::character varying as f8_5,
        concat('(9) ให้กำหนดจำนวนเงินหลักประกันการปฏิบัติตามสัญญาตามระเบียบกระทรวงการคลังว่าด้วยการจัดซื้อจัดจ้าง และการบริหารพัสดุภาครัฐ พ.ศ. 2560 ข้อ 168')::character varying as f9,
        concat('(10) เป็นข้อความหรือเงื่อนไขเพิ่มเติม ซึ่งหน่วยงานของรัฐผู้ทำสัญญาอาจเลือกใช้หรือตัดออกได้ตามข้อเท็จจริง')::character varying as f10,
        concat('(11) อัตราร้อยละที่ระบุไว้ต่อไปนี้ อาจพิจารณาแก้ไขได้ตามความเหมาะสม')::character varying as f11,
        concat('(12) เป็นข้อความหรือเงื่อนไขเพิ่มเติม ซึ่งหน่วยงานของรัฐผู้ทำสัญญาอาจเลือกใช้หรือตัดออกได้ตามข้อเท็จจริง')::character varying as f12,
        concat('(13) เป็นข้อความหรือเงื่อนไขเพิ่มเติม ซึ่งหน่วยงานของรัฐผู้ทำสัญญาอาจเลือกใช้หรือตัดออกได้ตามข้อเท็จจริง')::character varying as f13,
        concat('(14) เป็นข้อความหรือเงื่อนไขเพิ่มเติม ซึ่งหน่วยงานของรัฐผู้ทำสัญญาอาจเลือกใช้หรือตัดออกได้ตามข้อเท็จจริง')::character varying as f14,
        concat('(15) เป็นข้อความหรือเงื่อนไขเพิ่มเติม ซึ่งหน่วยงานของรัฐผู้ทำสัญญาอาจเลือกใช้หรือตัดออกได้ตามข้อเท็จจริง')::character varying as f15,
        concat('(16) ในกรณีที่หน่วยงานผู้ว่าจ้างเห็นเป็นการจำเป็นและสมควรจะหักค่าจ้างในแต่ละเดือนไว้จำนวนทั้งหมดก็ได้')::character varying as f16,
        concat('(17) เป็นข้อความหรือเงื่อนไขเพิ่มเติม ซึ่งหน่วยงานของรัฐผู้ทำสัญญาอาจเลือกใช้หรือตัดออกได้ตามข้อเท็จจริง')::character varying as f17,
        concat('(18) เป็นข้อความหรือเงื่อนไขเพิ่มเติม ซึ่งหน่วยงานของรัฐผู้ทำสัญญาอาจเลือกใช้หรือตัดออกได้ตามข้อเท็จจริง')::character varying as f18,
        concat('(19) เป็นข้อความหรือเงื่อนไขเพิ่มเติม ซึ่งหน่วยงานของรัฐผู้ทำสัญญาอาจเลือกใช้หรือตัดออกได้ตามข้อเท็จจริง')::character varying as f19,
        concat('(20) กำหนดเวลาที่ผู้รับจ้างจะรับผิดในความชำรุดบกพร่อง โดยปกติจะต้องกำหนด ไม่น้อยกว่า 2 ปี นับถัดจากวันที่ ผู้รับจ้างได้รับมอบงานจ้างก่อสร้าง')::character varying as f20,
        concat('(21) อัตราค่าปรับตามสัญญาข้อ 9 กรณีผู้รับจ้างไปจ้างช่วงบางส่วนโดยไม่ได้รับอนุญาต จากผู้ว่าจ้าง ต้องกำหนดค่าปรับ เป็นจำนวนเงินไม่น้อยกว่าร้อยละสิบของวงเงินของงานที่จ้างช่วงตามสัญญา')::character varying as f21,
        concat('(22) อัตราค่าปรับตามสัญญาข้อ 17 ให้กำหนดเป็นรายวันในอัตราระหว่างร้อยละ 0.01-0.10 ของราคางานจ้างนั้น ตามระเบียบกระทรวงการคลังว่าด้วยการจัดซื้อจัดจ้างและการบริหารพัสดุภาครัฐ พ.ศ. 2560 ข้อ 162 ส่วนกรณีจะปรับร้อยละเท่าใด ให้อยู่ในดุลพินิจของหน่วยงานของรัฐ ผู้ว่าจ้างที่จะพิจารณา โดยคำนึงถึงราคาและลักษณะของพัสดุที่จ้าง ซึ่งอาจมีผลกระทบต่อการที่ผู้รับจ้าง จะหลีกเลี่ยงไม่ปฏิบัติตามสัญญา แต่ทั้งนี้การที่จะกำหนดค่าปรับเป็นร้อยละเท่าใด จะต้องกำหนดไว้ ในเอกสารเชิญชวนด้วย')::character varying as f22,
        concat('(23) ถ้าต้องจ่ายค่าควบคุมงานวันละเท่าใด ให้เรียกค่าควบคุมงานจากผู้รับจ้างวันละเท่านั้น ตามจำนวนที่ล่วงเลย กำหนดสัญญาไป แต่สัญญาข้อนี้ไม่รวมถึงค่าควบคุมงานในกรณีที่ต้องต่ออายุสัญญา')::character varying as f23,
        concat('(24) เป็นข้อความหรือเงื่อนไขเพิ่มเติม ซึ่งหน่วยงานของรัฐผู้ทำสัญญาอาจเลือกใช้หรือตัดออกได้ตามข้อเท็จจริง')::character varying as f24,
		case when deapprove.personal_id is not null and deapprove.signature_image_id is not null
			then concat((select sp.parameter_value  from su_parameter sp 
							where sp.parameter_group_code = 'ContentPath'
							and sp.parameter_code = 'SignatureURL')
							,'?PersonalId=',deapprove.personal_id,'&ContentId=',deapprove.signature_image_id)
			else null end::character varying as recipient_sign_image,
		deapprove.emp_name::character varying AS sign_name
from po_pur_ord_master a 
left join ap_member am on a.ap_member_id = am.ap_member_id 
		left join ap_member_lang aml on aml.ap_member_id = am.ap_member_id and lower(aml.language_code) = lower(p_lin_id)
		left join db_prefix_lang aml2 on aml2.prefix_id = aml.prefix_id 
				and lower(aml2.language_code) = lower(p_lin_id)
left join db_employee_name(p_lin_id) deapprove on deapprove.emp_id = a.sign_id
where a.pur_ord_master_id = p_pur_ord_master_id;
    END;
$function$
;
